-- ============================================
-- SEED DATA: QA Elements (all 40)
-- ============================================
INSERT INTO public.qa_elements (qa_number, qa_name, standard_number, standard_name, element_code, element_name, concept, current_rating, officer_finding, meeting_criteria, exceeding_criteria, training_points) VALUES
-- QA1
(1, 'Educational Program and Practice', '1.1', 'The educational program enhances each child''s learning and development', '1.1.1', 'Approved learning framework', 'Curriculum decision making contributes to each child''s learning and development outcomes in relation to their identity, connection with community, wellbeing, confidence as learners and effectiveness as communicators.', 'not_met',
'Curriculum decision-making does not consistently demonstrate how individual children''s learning and development outcomes are being supported. Links between interests and planned experiences not clear.',
'Every program plan explicitly references EYLF V2.0 outcomes. Each child''s learning documented against EYLF outcomes. Educators can articulate EYLF links. All 5 outcomes addressed across the week.',
'Embedded: EYLF deeply woven into every aspect of programming. Critical Reflection: Team regularly reflects on how EYLF principles are embedded. Family/Community: Families understand the EYLF and how it shapes their child''s program.',
'Educators need training on EYLF V2.0 — 5 outcomes, 8 practices, 5 principles. Each room should have an EYLF reference sheet.'),

(1, 'Educational Program and Practice', '1.1', 'The educational program enhances each child''s learning and development', '1.1.2', 'Child-centred', 'Each child''s current knowledge, strengths, ideas, culture, abilities and interests are the foundation of the program.', 'not_met',
'While educators show awareness of children''s interests, the link between these and planned experiences is not clear. Children''s voices not explicitly integrated.',
'Programs begin with observed children''s interests. Children''s words/quotes documented. Each child''s cultural background considered. Clear links between observation and planning.',
'Embedded: Every experience traceable to children''s interests. Critical Reflection: Educators reflect on whose voices are heard. Family/Community: Families actively contribute cultural knowledge.',
'Practice writing observations capturing children''s interests. Role-play scenarios. Document the link between observation and planned experience.'),

(1, 'Educational Program and Practice', '1.1', 'The educational program enhances each child''s learning and development', '1.1.3', 'Program learning opportunities', 'All aspects of the program, including routines, are organised in ways that maximise opportunities for each child''s learning.', 'not_met',
'Routines not organised to maximise learning opportunities.',
'Mealtimes used for conversations, self-help skills, numeracy. Transitions include songs, movement, language games. Rest time includes quiet activities. Outdoor time has planned experiences.',
'Embedded: Every routine is a learning opportunity. Critical Reflection: Team reflects on which routines could be enhanced. Family/Community: Family routines respected and incorporated.',
'Walk through a typical day — identify every routine and brainstorm 3 ways to make each one a learning opportunity.'),

(1, 'Educational Program and Practice', '1.2', 'Educators facilitate and extend each child''s learning and development', '1.2.1', 'Intentional teaching', 'Educators are deliberate, purposeful, and thoughtful in their decisions and actions.', 'not_met',
'Minimal evidence of consistent intentional teaching. Learning environments not strategically arranged.',
'Educators plan specific intentional teaching strategies. Environments strategically arranged to provoke inquiry. Resources purposefully positioned. Educators explain their environment choices.',
'Embedded: Intentional teaching is second nature. Critical Reflection: Educators reflect on strategy effectiveness. Family/Community: Families understand intentional teaching.',
'Video analysis of intentional teaching examples. Practice setting up environments with intention.'),

(1, 'Educational Program and Practice', '1.2', 'Educators facilitate and extend each child''s learning and development', '1.2.2', 'Responsive teaching and scaffolding', 'Educators respond to children''s ideas and play and extend children''s learning through open-ended questions, interactions and feedback.', 'not_met',
'Open-ended questions, scaffolding, and deliberate extension of learning were inconsistent.',
'Educators use open-ended questions consistently. Sustained shared thinking practised. Scaffolding provides just enough support. Evidence in documentation.',
'Embedded: Every educator demonstrates sustained shared thinking. Critical Reflection: Educators analyse their questioning techniques. Family/Community: Families encouraged to use open-ended questions.',
'Practice sessions generating open-ended questions. Record and review educator-child interactions.'),

(1, 'Educational Program and Practice', '1.2', 'Educators facilitate and extend each child''s learning and development', '1.2.3', 'Child directed learning', 'Each child''s agency is promoted, enabling them to make choices and decisions that influence events and their world.', 'not_met',
'Opportunities for child-directed learning not evident including making choices, influencing routines, or contributing to planning.',
'Children choose activities, materials, and play partners. Children influence routines. Children contribute to planning. Physical environment supports independence.',
'Embedded: Children are genuine decision-makers. Critical Reflection: Educators reflect on power dynamics and equitable access to choice. Family/Community: Cultural perspectives on child autonomy respected.',
'Each room identifies 5 moments where children can have more choice. Create visual choice boards.'),

(1, 'Educational Program and Practice', '1.3', 'Educators and co-ordinators take a planned and reflective approach', '1.3.1', 'Assessment and planning cycle', 'Each child''s learning and development is assessed or evaluated as part of an ongoing cycle of observation, analysing learning, documentation, planning, implementation and reflection.', 'not_met',
'Service unable to demonstrate a complete planning cycle. EL and NS unable to locate a complete planning cycle for any child. Breach of Regulation 74.',
'Complete documented cycle for each child: Observation → Analysis → Goals → Planning → Implementation → Reflection → Follow-up. Regular observations (minimum fortnightly). Clear links throughout.',
'Embedded: The cycle operates seamlessly as part of daily practice. Critical Reflection: Team evaluates the effectiveness of the planning cycle itself. Family/Community: Families contribute to and receive information from the cycle.',
'Walk through a complete planning cycle for one child as a team. Practice writing observations with analysis.'),

(1, 'Educational Program and Practice', '1.3', 'Educators and co-ordinators take a planned and reflective approach', '1.3.2', 'Critical reflection', 'Critical reflection on children''s learning and development, both as individuals and in groups, drives program planning and implementation.', 'not_met',
'Critical reflection inconsistent, not driving planning.',
'Weekly documented critical reflections. Reflections address what worked, why, and what to change. Direct link to program changes. All educators contribute.',
'Embedded: Reflection is deeply embedded. Critical Reflection: Team draws on theory, research, and multiple perspectives. Family/Community: Diverse viewpoints challenge and enrich practice.',
'Critical reflection workshop: "What happened" → "So what?" → "Now what?". Provide reflective prompts.'),

(1, 'Educational Program and Practice', '1.3', 'Educators and co-ordinators take a planned and reflective approach', '1.3.3', 'Information for families', 'Families are informed about the program and their child''s progress.', 'not_met',
'Family contributions minimal. Service awaiting return of information sheets.',
'Families regularly informed about the program. Families receive progress information. Families contribute to the program. Multiple communication methods used.',
'Embedded: Two-way communication is rich and ongoing. Critical Reflection: Team reflects on whether all families are equally engaged. Family/Community: Diverse communication preferences accommodated.',
'Discuss effective family communication strategies. Practice writing meaningful learning stories.'),

-- QA2
(2, 'Children''s Health and Safety', '2.1', 'Each child''s health and physical activity is supported and promoted', '2.1.1', 'Wellbeing and comfort', 'Each child''s wellbeing and comfort is provided for, including appropriate opportunities to meet each child''s need for sleep, rest and relaxation.', 'met',
'Children''s individual needs for rest and relaxation are partially supported. Beds available and educators provide quiet activities.',
'Individual sleep/rest needs met. Children''s emotional wellbeing supported. Quiet spaces available.',
'Embedded: Every child''s individual wellbeing needs are known and consistently met. Critical Reflection: Educators reflect on changing wellbeing needs. Family/Community: Cultural practices around rest respected.',
'Maintain current practices. Ensure individual rest plans documented.'),

(2, 'Children''s Health and Safety', '2.1', 'Each child''s health and physical activity is supported and promoted', '2.1.2', 'Health practices and procedures', 'Effective illness and injury management and hygiene practices are promoted and implemented.', 'not_met',
'Hygiene and food handling practices inconsistent. Handwashing not actively monitored. Reg 77 non-compliance.',
'Handwashing at all required times. Educators actively supervise handwashing. Food handling meets regulations. Illness prevention practices followed consistently.',
'Embedded: Hygiene practices are second nature. Children independently follow health routines. Critical Reflection: Team reviews illness data to identify patterns. Family/Community: Families informed about health practices.',
'Handwashing demonstration. Food safety refresher. Create visual handwashing reminders.'),

(2, 'Children''s Health and Safety', '2.1', 'Each child''s health and physical activity is supported and promoted', '2.1.3', 'Healthy lifestyle', 'Healthy eating and physical activity are promoted and appropriate for each child.', 'not_met',
'Healthy eating opportunities implemented but not consistently planned. Fundamental movement skill development not structured.',
'Structured daily physical activity. FMS program (running, jumping, balancing, throwing, catching). Munch & Move guidelines implemented. Mealtimes as learning experiences.',
'Embedded: Physical activity and healthy eating woven throughout the day. Critical Reflection: Educators evaluate whether activities meet diverse needs. Family/Community: Families contribute cultural food knowledge.',
'Munch & Move training. Plan FMS activities. Embed nutrition conversations in mealtimes.'),

(2, 'Children''s Health and Safety', '2.2', 'Each child is protected', '2.2.1', 'Supervision', 'At all times, reasonable precautions and adequate supervision ensure children are protected from harm and hazard.', 'not_met',
'Supervision not consistently in place. Section 165 breach — sleeping child not visible to educator.',
'All children visible at all times. Educators positioned strategically. Supervision plans actively used. Sleeping children checked and visible.',
'Embedded: Supervision is proactive, not reactive. Educators anticipate risks. Critical Reflection: Team reviews incidents to improve. Family/Community: Families informed about supervision practices.',
'Supervision positioning exercise — draw room maps. Practice scanning while engaging.'),

(2, 'Children''s Health and Safety', '2.2', 'Each child is protected', '2.2.2', 'Incident and emergency management', 'Plans to effectively manage incidents and emergencies are developed in consultation with relevant authorities, practised and implemented.', 'not_met',
'Emergency drills not in required timeframes. Risk assessment undated. Reg 97 breaches.',
'Drills every 3 months documented with reflections. Improvements actioned. Risk assessment dated and reviewed annually. All educators know their roles.',
'Embedded: Emergency preparedness is natural. All educators confident in their roles. Critical Reflection: Drill reflections lead to genuine improvements. Family/Community: Families informed about procedures.',
'Emergency roles session. Conduct a drill and debrief. Review and date the risk assessment.'),

(2, 'Children''s Health and Safety', '2.2', 'Each child is protected', '2.2.3', 'Child safety and protection', 'Management, educators and staff are aware of their roles and responsibilities regarding child safety, including the need to identify and respond to every child at risk of abuse or neglect.', 'not_met',
'NS could not demonstrate knowledge of Reportable Conduct Scheme. Educator unable to explain reportable conduct. Reg 84 breach.',
'ALL staff can explain mandatory reporting and Reportable Conduct Scheme. Training completed and documented. Procedures clear. Discussed in team meetings.',
'Embedded: Child safety central to culture. Every educator confident in obligations. Critical Reflection: Team examines potential blind spots. Family/Community: ACECQA Child Safe Culture Guide used.',
'CRITICAL: Comprehensive child protection session — mandatory reporting, Reportable Conduct Scheme, practical scenarios.'),

-- QA3
(3, 'Physical Environment', '3.1', 'The design of the facilities is appropriate for the operation of a service', '3.1.1', 'Fit for purpose', 'Outdoor and indoor spaces, buildings, fixtures and fittings are suitable for their purpose, including supporting the access of every child.', 'met',
'Indoor and outdoor environments generally suitable. Spacious layouts, open shelving, child-height furniture.',
'Spaces suitable for all children including those with additional needs. Regular maintenance documented.',
'Embedded: Environments universally designed. Critical Reflection: Team regularly evaluates fitness for purpose. Family/Community: Family input guides improvements.', ''),

(3, 'Physical Environment', '3.1', 'The design of the facilities is appropriate for the operation of a service', '3.1.2', 'Upkeep', 'Premises, furniture and equipment are safe, clean and well maintained.', 'met',
'Cleaning, maintenance, and safety checks conducted. Minor adjustment offered for tunnel wire.',
'Regular documented maintenance checks. Issues addressed promptly. Clean, safe environment maintained.',
'Embedded: Maintenance is proactive. Critical Reflection: Team identifies patterns in maintenance needs. Family/Community: Families can raise concerns.', ''),

(3, 'Physical Environment', '3.2', 'The service environment is inclusive, promotes competence and supports exploration and play-based learning', '3.2.1', 'Inclusive environment', 'Outdoor and indoor spaces are organised and adapted to support every child''s participation.', 'not_met',
'Practices inconsistent across rooms. Limited intentional setups. Inclusion not systematic. Soft cushions removed.',
'Spaces intentionally arranged. Quiet/calm spaces in every room. Environments adapted for additional needs. Culturally inclusive resources visible.',
'Embedded: Every child can participate meaningfully. Critical Reflection: Educators evaluate environments for inclusiveness. Family/Community: Inclusion Agency supports adaptations.',
'Environmental audit together. Practice creating intentional setups. Discuss culturally responsive environments.'),

(3, 'Physical Environment', '3.2', 'The service environment is inclusive, promotes competence and supports exploration and play-based learning', '3.2.2', 'Resources support play-based learning', 'Resources, materials and equipment allow for multiple uses, are sufficient in number, and enable every child to engage in play-based learning.', 'met',
'Resources accessible including natural and recycled items.',
'Diverse open-ended resources available. Adequate quantity. Natural and recycled materials included.',
'Embedded: Resources are rich, varied, and continuously refreshed. Critical Reflection: Team evaluates resource quality and relevance. Family/Community: Families contribute resources.', ''),

(3, 'Physical Environment', '3.2', 'The service environment is inclusive, promotes competence and supports exploration and play-based learning', '3.2.3', 'Environmentally responsible', 'The service cares for the environment and supports children to become environmentally responsible.', 'not_met',
'No recycling bins in rooms. Educator stepped on spider without discussion. Sustainability not systematic.',
'Recycling/compost/rubbish bins in each room. Sustainability in program. Natural encounters used as learning. Children involved in caring for environment.',
'Embedded: Sustainability part of service culture. Critical Reflection: Team reflects on environmental footprint. Family/Community: Families contribute to sustainability initiatives.',
'Sustainability brainstorm — 20 ways to embed it. Discuss responding to nature encounters. Plan a garden project.'),

-- QA4
(4, 'Staffing Arrangements', '4.1', 'Staffing arrangements enhance children''s learning and development', '4.1.1', 'Organisation of educators', 'The organisation of educators across the service supports children''s learning and development.', 'met',
'Educators deployed effectively. Ratios maintained.',
'Ratios maintained at all times. Educators effectively deployed. Clear responsibilities during routines.',
'Embedded: Organisation seamless. Critical Reflection: Team reviews effectiveness. Family/Community: Families informed about staffing.', ''),

(4, 'Staffing Arrangements', '4.1', 'Staffing arrangements enhance children''s learning and development', '4.1.2', 'Continuity of staff', 'Every effort is made for children to experience continuity of educators at the service.', 'met',
'Regular educators allocated consistently.',
'Consistent educator allocation. Efforts to minimise disruption from casual staff.',
'Embedded: Children have strong bonds with regular educators. Critical Reflection: Team examines impact of staff changes. Family/Community: Families know their child''s regular educators.', ''),

(4, 'Staffing Arrangements', '4.2', 'Management, educators and staff are collaborative, respectful and ethical', '4.2.1', 'Professional collaboration', 'Management, educators and staff work with mutual respect and collaboratively.', 'not_met',
'Team meetings inconsistent (only 2-3 since Jul 2025). Minutes lack substance. Staff handbook generic template. Tense interactions observed.',
'Monthly meetings with structured agenda. Minutes document discussions and actions. Staff handbook customised. Respectful relationships.',
'Embedded: Collaboration is the norm. Educators actively seek input. Critical Reflection: Team examines power dynamics. Family/Community: Collaboration extends to families and community.',
'How to run effective team meetings. Structured agenda template. Conflict resolution strategies.'),

(4, 'Staffing Arrangements', '4.2', 'Management, educators and staff are collaborative, respectful and ethical', '4.2.2', 'Professional standards', 'Professional standards guide practice, interactions and relationships.', 'not_met',
'Formal systems for collaboration, reflection, and professional standards not in place.',
'Code of conduct signed and understood. PD plans for each educator. Performance reviews conducted. Mentoring documented.',
'Embedded: Professional standards are lived. Critical Reflection: Educators critically reflect on own practice. Family/Community: Professional standards visible to families.',
'Code of conduct refresher. Setting professional goals. Giving and receiving feedback.'),

-- QA5
(5, 'Relationships with Children', '5.1', 'Respectful and equitable relationships are maintained with each child', '5.1.1', 'Positive educator to child interactions', 'Responsive and meaningful interactions build trusting relationships which engage and support each child to feel secure, confident and included.', 'not_met',
'Inconsistent across rooms. Some educators used directive or stern language. Multiple Reg 155 breaches documented.',
'Warm responsive interactions with every child. Calm supportive encouraging language. Educators get down to children''s level. Feelings acknowledged.',
'Embedded: Positive interactions natural and consistent. Emotional climate warm and joyful. Critical Reflection: Educators regularly reflect on interaction quality. Family/Community: Families feel welcomed.',
'PRIORITY: Review Reg 155. Alternative language practice. Role-play scenarios. Video self-reflection.'),

(5, 'Relationships with Children', '5.1', 'Respectful and equitable relationships are maintained with each child', '5.1.2', 'Dignity and rights of the child', 'The dignity and rights of every child are maintained.', 'not_met',
'Stern language impacts dignity. Multiple Reg 155 breaches.',
'Children''s rights upheld at all times. No shaming or humiliating language. Cultural values respected. Privacy maintained.',
'Embedded: Culture of respect permeates every interaction. Critical Reflection: Team examines practices through rights-based lens. Family/Community: Cultural perspectives on childhood respected.',
'Children''s rights workshop. UN Convention on the Rights of the Child discussion.'),

(5, 'Relationships with Children', '5.2', 'Each child is supported to build and maintain sensitive and responsive relationships', '5.2.1', 'Collaborative learning', 'Children are supported to collaborate, learn from and help each other.', 'not_met',
'Insufficient intentional collaborative learning. Educators not consistently modelling cooperation.',
'Planned group activities requiring teamwork. Educators model cooperative behaviours. Children supported to help each other. Collaborative projects documented.',
'Embedded: Collaboration visible throughout. Children naturally help each other. Critical Reflection: Educators reflect on group dynamics. Family/Community: Families involved in projects.',
'Plan 3 collaborative learning experiences per room per week. Practice facilitating group projects.'),

(5, 'Relationships with Children', '5.2', 'Each child is supported to build and maintain sensitive and responsive relationships', '5.2.2', 'Self-regulation', 'Each child is supported to regulate their own behaviour, respond appropriately to the behaviour of others and communicate effectively to resolve conflicts.', 'not_met',
'Directive language, forced compliance, physical restraint used. No calm-down spaces. Behaviour reports contain speculative language. Multiple Reg 156 breaches.',
'Calm-down spaces in each room. Co-regulation strategies used. Children supported to name emotions. Conflict resolution modelled. Behaviour documentation records facts.',
'Embedded: Self-regulation support woven into every interaction. Children increasingly manage own emotions. Critical Reflection: Team examines behaviour guidance against research. Family/Community: Families are partners in strategies.',
'PRIORITY: Self-regulation strategies workshop. Co-regulation practice. Setting up calm-down spaces. Behaviour documentation training.'),

-- QA6
(6, 'Collaborative Partnerships with Families and Communities', '6.1', 'Respectful relationships with families are developed and maintained', '6.1.1', 'Engagement with the service', 'Families are supported from enrolment to be involved in the service and contribute to service decisions.', 'not_met',
'Formal communication inconsistent. No current family surveys. Feedback not documented.',
'Regular communication via multiple channels. Orientation welcoming. Family feedback sought through surveys. Feedback documented and acted upon.',
'Embedded: Family engagement genuine and reciprocal. Critical Reflection: Team reflects on which families are engaged and barriers. Family/Community: Diverse backgrounds equally valued.',
'Family communication strategies. Writing effective newsletters. Using Playground app consistently.'),

(6, 'Collaborative Partnerships with Families and Communities', '6.1', 'Respectful relationships with families are developed and maintained', '6.1.2', 'Parents views are respected', 'The expertise, culture, values and beliefs of families are respected and families share in decision-making about their child''s learning and wellbeing.', 'not_met',
'Decision-making limited to informal verbal conversations.',
'Families contribute to their child''s program. Family input documented and acted upon. Formal opportunities for views. Cultural values respected.',
'Embedded: Families are genuine decision-making partners. Critical Reflection: Educators reflect on whether family perspectives genuinely influence practice. Family/Community: Power imbalances acknowledged.',
'How to conduct family meetings. Active listening skills. Cultural competency.'),

(6, 'Collaborative Partnerships with Families and Communities', '6.1', 'Respectful relationships with families are developed and maintained', '6.1.3', 'Families are supported', 'Current information is available to families about the service and relevant community services and resources to support parenting and family wellbeing.', 'not_met',
'Community services information not consistently provided.',
'Community resources displayed. Families referred to support services. Parenting resources shared. Educators aware of local services.',
'Embedded: Service is a hub connecting families with community. Critical Reflection: Team evaluates whether families access support. Family/Community: Strong partnerships with community services.',
'Know your community resources. How to make sensitive referrals. Community resource board.'),

(6, 'Collaborative Partnerships with Families and Communities', '6.2', 'Collaborative partnerships enhance children''s inclusion, learning and wellbeing', '6.2.1', 'Transitions', 'Continuity of learning and transitions for each child are supported by sharing information and clarifying responsibilities.', 'not_met',
'Limited systematic information sharing for transitions.',
'Enrolment transition structured and documented. Room-to-room transitions planned. School transition supported. Children supported emotionally.',
'Embedded: Transitions seamless and positive. Every transition individually planned. Critical Reflection: Team reflects on transition improvements. Family/Community: Partnerships with schools.',
'Develop transition procedures. Create transition summary templates.'),

(6, 'Collaborative Partnerships with Families and Communities', '6.2', 'Collaborative partnerships enhance children''s inclusion, learning and wellbeing', '6.2.2', 'Access and participation', 'Effective partnerships support children''s access, inclusion and participation in the program.', 'not_met',
'No individualised support plans. Child with high needs had limited environmental support. Diagnosis received day before visit.',
'Individualised support plans for children with additional needs. Strategies developed with families and allied health. Environment adapted. ISP funding accessed.',
'Embedded: Inclusion proactive and embedded. Universal design. Critical Reflection: Team examines whether all children genuinely participate. Family/Community: Allied health professionals collaborate.',
'Inclusive practice workshop. Developing support plans. Working with allied health.'),

(6, 'Collaborative Partnerships with Families and Communities', '6.2', 'Collaborative partnerships enhance children''s inclusion, learning and wellbeing', '6.2.3', 'Community engagement', 'The service builds relationships and engages with its local community.', 'not_met',
'Limited partnerships. No excursions. Minimal community collaboration.',
'Partnerships with local organisations. Excursions occurring. Community members contribute. Referral pathways documented.',
'Embedded: Service deeply connected to community. Critical Reflection: Team evaluates partnerships. Family/Community: Partnerships driven by children and family needs.',
'Community mapping exercise. Plan an excursion. Invite a community member.'),

-- QA7
(7, 'Governance and Leadership', '7.1', 'Governance supports the operation of a quality service that is child safe', '7.1.1', 'Service philosophy and purpose', 'A statement of philosophy guides all aspects of the service''s operations.', 'not_met',
'Philosophy input from families, children, and community minimal. Limited consultation documented.',
'Philosophy guides all operations. Developed with stakeholder input. Reviewed regularly with documented feedback. Educators can articulate it.',
'Embedded: Philosophy is a living document shaping every decision. Critical Reflection: Team interrogates the philosophy regularly. Family/Community: Families and community actively contribute.',
'Philosophy workshop — what K.I.R.O.S means in daily practice. How to gather input.'),

(7, 'Governance and Leadership', '7.1', 'Governance supports the operation of a quality service that is child safe', '7.1.2', 'Management systems', 'Systems are in place to manage risk and enable the effective management and operation of a quality service that is child safe.', 'not_met',
'Informal leadership. No documented casual induction. Significant governance gaps. Section 172(3)(a) breach.',
'Clear governance structure documented. Formal induction for ALL staff including casuals. Compliance monitoring systems. Policies reviewed on schedule.',
'Embedded: Management systems robust and well-understood. Critical Reflection: Governance practices regularly evaluated. Family/Community: Transparency prioritised.',
'Induction process training. Compliance monitoring overview. Policy review procedures.'),

(7, 'Governance and Leadership', '7.1', 'Governance supports the operation of a quality service that is child safe', '7.1.3', 'Roles and responsibilities', 'Roles and responsibilities are clearly defined, and understood, and support effective decision making and operation of the service.', 'not_met',
'Roles not clearly defined. Delegation and accountability inconsistent.',
'Position descriptions for all roles. Clear delegation. Staff understand reporting lines. Accountability processes.',
'Embedded: Roles clearly understood, staff work autonomously. Critical Reflection: Team reviews role effectiveness. Family/Community: Families know who to approach.', ''),

(7, 'Governance and Leadership', '7.2', 'Effective leadership builds and promotes a positive organisational culture and professional learning community', '7.2.1', 'Continuous improvement', 'There is an effective self-assessment and quality improvement process in place.', 'not_met',
'QIP accessible but implementation limited.',
'QIP regularly reviewed and updated. SMART actions. Progress tracked. All stakeholders contribute. Self-assessment informs priorities.',
'Embedded: Continuous improvement part of culture. Critical Reflection: Team regularly assesses progress. Family/Community: Families contribute to improvement goals.', ''),

(7, 'Governance and Leadership', '7.2', 'Effective leadership builds and promotes a positive organisational culture and professional learning community', '7.2.2', 'Educational leadership', 'The educational leader is supported and leads the development and implementation of the educational program and assessment and planning cycle.', 'not_met',
'EL provides occasional mentoring but no formal PD plans or structured coaching. No consistent off-floor time.',
'EL has dedicated off-floor time. Leads curriculum development. Mentors and coaches educators (documented). Supports the planning cycle.',
'Embedded: Educational leadership strong and visible. Critical Reflection: EL engages in critical reflection on own leadership. Family/Community: EL communicates with families about program.',
'Educational leadership plan development. Mentoring and coaching skills.'),

(7, 'Governance and Leadership', '7.2', 'Effective leadership builds and promotes a positive organisational culture and professional learning community', '7.2.3', 'Development of professionals', 'Educators, co-ordinators and staff members'' performance is regularly evaluated and individual plans are in place to support learning and development.', 'not_met',
'Performance reviews emerging. Brief catch-ups. No mid-year reviews. Limited PD.',
'PD plan for each educator. Performance reviews regularly (quarterly minimum). PD aligned with service priorities. PD documented.',
'Embedded: PD prioritised and valued. Educators growing and bringing new ideas. Critical Reflection: PD effectiveness evaluated. Family/Community: PD includes engagement with families.',
'');

-- ============================================
-- SEED DATA: Compliance Items
-- ============================================
INSERT INTO public.compliance_items (regulation, description, status, notes) VALUES
('Regulation 74', 'Document child assessments/evaluations for delivery of educational program', 'action_required', 'Complete planning cycle must be implemented for each child'),
('Regulation 77', 'Health, hygiene, and safe food handling practices', 'action_required', 'Handwashing protocols and food handling procedures need reinforcement'),
('Regulation 84', 'All persons working with children must be aware of child protection law', 'action_required', 'All staff need comprehensive child protection training including Reportable Conduct Scheme'),
('Regulation 97(2A)', 'Potential Emergency Risk Assessment must be dated and reviewed annually', 'completed', 'Risk assessment has been dated and reviewed'),
('Regulation 97(3)(a)', 'Emergency and evacuation procedures rehearsed at least every 3 months', 'action_required', 'Strict 3-monthly drill calendar must be implemented'),
('Regulation 155', 'Interactions with children must encourage expression, support self-reliance, maintain dignity, provide positive guidance', 'in_progress', 'Previous NS removed. Educator training on positive interactions conducted. Positive language framework introduced.'),
('Regulation 156', 'Relationships in groups must support respectful positive relationships', 'in_progress', 'Training on self-regulation strategies. Calm-down spaces established.'),
('Section 165', 'Children must be adequately supervised at all times', 'in_progress', 'Supervision review conducted. Room layouts adjusted for sight lines.'),
('Section 172(3)(a)', 'Display prescribed information (compliance history) at main entrance', 'action_required', 'Download correct short-form compliance history from NSW Early Learning Commission website and display');

-- ============================================
-- SEED DATA: Training Modules
-- ============================================
INSERT INTO public.training_modules (title, description, duration_hours, sort_order, related_qa, related_regulations, content) VALUES
('Positive Interactions and Language', 'PRIORITY — Understanding Regulation 155/156, impact of language on children, alternative language strategies, co-regulation and self-regulation support', 2.0, 1, 'QA5', 'Reg 155, Reg 156', 'Module content migrated from Quality Uplift Portal'),
('The Planning Cycle', 'Understanding the complete assessment and planning cycle, writing meaningful observations, linking to EYLF outcomes, critical reflection', 2.0, 2, 'QA1', 'Reg 74', 'Module content migrated from Quality Uplift Portal'),
('Child Protection and Reportable Conduct', 'Mandatory reporting obligations in NSW, Reportable Conduct Scheme, steps to take, documentation requirements', 1.5, 3, 'QA2', 'Reg 84', 'Module content migrated from Quality Uplift Portal'),
('Intentional Teaching and Scaffolding', 'Intentional teaching vs direct instruction, scaffolding techniques, open-ended questioning, sustained shared thinking', 1.5, 4, 'QA1', '', 'Module content migrated from Quality Uplift Portal'),
('Health, Hygiene, and Safety', 'Handwashing requirements, food handling, supervision standards', 1.0, 5, 'QA2', 'Reg 77', 'Module content migrated from Quality Uplift Portal'),
('Emergency Procedures', 'Emergency roles and responsibilities, conducting drills, reflection and improvement', 0.75, 6, 'QA2', 'Reg 97', 'Module content migrated from Quality Uplift Portal'),
('Family Engagement and Communication', 'Effective communication strategies, gathering family input, managing challenging conversations', 1.0, 7, 'QA6', '', 'Module content migrated from Quality Uplift Portal'),
('Environmental Sustainability', 'Recycling and composting, nature encounters as learning, gardening, Caring for Country', 0.75, 8, 'QA3', '', 'Module content migrated from Quality Uplift Portal');

-- ============================================
-- SEED DATA: Resources
-- ============================================
INSERT INTO public.resources (title, url, description, qa_area, sort_order) VALUES
